New-Item -ItemType Directory -Force -Path $TargetDir | Out-Null
foreach ($file in $files) {
    $path = Join-Path $TargetDir $file.Path
    $parent = Split-Path -Parent $path
    if (-not [string]::IsNullOrWhiteSpace($parent)) {
        New-Item -ItemType Directory -Force -Path $parent | Out-Null
    }
    [System.IO.File]::WriteAllBytes($path, [Convert]::FromBase64String($file.Content))
}

Write-Host "Created ClassDiagramMaker source at $TargetDir (20 files)"
Write-Host "Run on Windows: cd $TargetDir; dotnet run --project src/ClassDiagramMaker/ClassDiagramMaker.csproj"
Write-Host "Publish single exe: .\tools\publish-single-exe.ps1"
